"use strict";(self.webpackChunkblogv2_dev=self.webpackChunkblogv2_dev||[]).push([[3807],{570:(e,t,p)=>{p.r(t),p.d(t,{data:()=>o});const o={key:"v-760cfeb4",path:"/blogs/Others/zen_of_python.html",title:"The Zen of Python",lang:"zh-CN",frontmatter:{title:"The Zen of Python",Date:"2017-1-1",tag:["python"],category:["Others"],sticky:1,sidebar:!1,summary:"\nZon of Python -- By Tim Peters\n翻译 -- weigao chen\n\n",head:[["meta",{property:"og:url",content:"https://vueblog.weigao.cc/blogs/Others/zen_of_python.html"}],["meta",{property:"og:site_name",content:"WW"}],["meta",{property:"og:title",content:"The Zen of Python"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-04-17T08:12:32.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:tag",content:"python"}],["meta",{property:"article:modified_time",content:"2022-04-17T08:12:32.000Z"}]]},excerpt:"<blockquote>\n<p>Zon of Python -- By Tim Peters</p>\n<p>翻译 -- weigao chen</p>\n</blockquote>\n",headers:[],git:{createdTime:1644237761e3,updatedTime:1650183152e3,contributors:[{name:"chenweigao",email:"297859260@qq.com",commits:2},{name:"chenweigao",email:"chenweigao1@huawei.com",commits:1}]},readingTime:{minutes:.96,words:287},filePathRelative:"blogs/Others/zen_of_python.md"}},3811:(e,t,p)=>{p.r(t),p.d(t,{default:()=>r});var o=p(6252);const n=(0,o._)("blockquote",null,[(0,o._)("p",null,"Zon of Python -- By Tim Peters"),(0,o._)("p",null,"翻译 -- weigao chen")],-1),a=(0,o.uE)("<p>Beautiful is better than ugly.</p><p>Explicit is better than implicit.</p><p>于美于显，勿陋勿隐。</p><p>Simple is better than complex.</p><p>Complex is better than complicated.</p><p>何彼繁矣，大道至简。</p><p>何彼涩矣，涩以从繁。</p><p>（吾心繁繁，愠于从涩）</p><p>Flat is better than nested.</p><p>Sparse is better than dense.</p><p>平兮稀兮，实获我心。</p><p>嵌兮密兮，心之忧矣。</p><p>Readability counts.</p><p>读之妙哉，日就月将。</p><p>Special cases aren&#39;t special enough to break the rules.</p><p>殊从于规，不可破也。</p><p>所可破也，行之厉也。</p><p>Although practicality beats purity.</p><p>Errors should never pass silently.</p><p>Unless explicitly silenced.</p><p>岂不思异，过莫避之。</p><p>In the face of ambiguity, refuse the temptation to guess.</p><p>There should be one-- and preferably only one --obvious way to do it.</p><p>远歧近理，闻于苍穹。</p><p>Although that way may not be obvious at first unless you&#39;re Dutch.</p><p>Now is better than never.</p><p>Although never is often better than <em>right</em> now.</p><p>其艰不易，何不躬行？</p><p>夙夜解之，既明且哲。</p><p>If the implementation is hard to explain, it&#39;s a bad idea.</p><p>If the implementation is easy to explain, it may be a good idea.</p><p>解之即成，于简于繁？</p><p>简兮简兮，以永终誉。</p><p>繁兮繁兮，于乎哀哉！</p><p>Namespaces are one honking great idea -- let&#39;s do more of those!</p><p>命名空间，于嗟益兮！</p>",36),i={},r=(0,p(3744).Z)(i,[["render",function(e,t){return(0,o.wg)(),(0,o.iD)("div",null,[n,(0,o.kq)(" more "),a])}]])},3744:(e,t)=>{t.Z=(e,t)=>{const p=e.__vccOpts||e;for(const[e,o]of t)p[e]=o;return p}}}]);